node -e "
const manifest = require('./manifest.json');
const schema = require('./schema.json');

let errors = [];

// top-level: only 'release' and 'components' allowed (additionalProperties: false)
const topKeys = Object.keys(manifest);
const allowedTop = Object.keys(schema.properties);
const extraTop = topKeys.filter(k => !allowedTop.includes(k));
if (extraTop.length) errors.push('Extra top-level keys: ' + extraTop);

// release pattern
if (!/^v[0-9]+\.[0-9]+\.[0-9]+$/.test(manifest.release))
  errors.push('release does not match pattern: ' + manifest.release);

// components array
if (!Array.isArray(manifest.components)) errors.push('components is not an array');
else {
  if (manifest.components.length !== 3) errors.push('components length: ' + manifest.components.length);
  manifest.components.forEach((c, i) => {
    const ckeys = Object.keys(c);
    const extra = ckeys.filter(k => !['name','version'].includes(k));
    if (extra.length) errors.push('component[' + i + '] extra keys: ' + extra);
    if (typeof c.name !== 'string' || c.name.length < 1) errors.push('component[' + i + '] bad name');
    if (!/^[0-9]+\.[0-9]+\.[0-9]+$/.test(c.version)) errors.push('component[' + i + '] bad version: ' + c.version);
  });
  // uniqueItems
  const strs = manifest.components.map(c => JSON.stringify(c));
  if (new Set(strs).size !== strs.length) errors.push('components not unique');
  // order
  if (manifest.components[0].name !== 'catalog') errors.push('wrong order[0]');
  if (manifest.components[1].name !== 'fetcher') errors.push('wrong order[1]');
  if (manifest.components[2].name !== 'leaderboard') errors.push('wrong order[2]');
}

if (errors.length === 0) console.log('ALL CHECKS PASSED');
else errors.forEach(e => console.log('FAIL:', e));
" 2>/dev/null
